#include <stdio.h>
#include <stdlib.h>

#define T 3  // Minimum degree

typedef struct BTreeNode {
    int keys[2*T - 1];
    struct BTreeNode *children[2*T];
    int numKeys;
    int isLeaf;
} BTreeNode;

BTreeNode* createNode(int isLeaf) {
    BTreeNode* node = (BTreeNode*)malloc(sizeof(BTreeNode));
    node->numKeys = 0;
    node->isLeaf = isLeaf;
    return node;
}

void splitChild(BTreeNode* parent, int index) {
    BTreeNode* child = parent->children[index];
    BTreeNode* newNode = createNode(child->isLeaf);

    // New node gets t-1 keys from child
    newNode->numKeys = T - 1;
    for (int j = 0; j < T - 1; j++)
        newNode->keys[j] = child->keys[j + T];

    // Move children if not leaf
    if (!child->isLeaf) {
        for (int j = 0; j < T; j++)
            newNode->children[j] = child->children[j + T];
    }

    // Reduce keys in child
    child->numKeys = T - 1;

    // Move parent child pointers
    for (int j = parent->numKeys; j > index; j--)
        parent->children[j + 1] = parent->children[j];
    parent->children[index + 1] = newNode;

    // Move median key up to parent
    for (int j = parent->numKeys - 1; j >= index; j--)
        parent->keys[j + 1] = parent->keys[j];
    parent->keys[index] = child->keys[T - 1];
    parent->numKeys++;
}

class BTree {
    private int t;  // minimum degree
    private Node root;

    private class Node {
        int[] keys;
        Node[] children;
        int n;  // current number of keys
        boolean leaf;

        Node(boolean leaf) {
            this.leaf = leaf;
            this.keys = new int[2*t - 1];
            this.children = new Node[2*t];
            this.n = 0;
        }
    }

    public Node search(int k) {
        return search(root, k);
    }

    private Node search(Node x, int k) {
        int i = 0;
        while (i < x.n && k > x.keys[i])
            i++;

        if (i < x.n && k == x.keys[i])
            return x;  // Found

        if (x.leaf)
            return null;  // Not found

        return search(x.children[i], k);
    }

    public void traverse() {
        traverse(root);
    }

    private void traverse(Node x) {
        if (x != null) {
            int i;
            for (i = 0; i < x.n; i++) {
                if (!x.leaf)
                    traverse(x.children[i]);
                System.out.print(x.keys[i] + " ");
            }
            if (!x.leaf)
                traverse(x.children[i]);
        }
    }
}
